// Agent Feedback Store
const sd = $getWorkflowStaticData('global');
sd.feedback = sd.feedback || {};

const input = $input.first().json || {};
const q = input.query || {};
const body = input.body || {};

// READ — query has action=read OR no body fields
if (q.action === 'read' || (!body.agentId && !body.comment)) {
  if (q.agentId) {
    return [{ json: { agentId: q.agentId, feedback: sd.feedback[q.agentId] || [] } }];
  }
  const summary = {};
  for (const aid of Object.keys(sd.feedback)) {
    summary[aid] = (sd.feedback[aid] || []).length;
  }
  return [{ json: { feedbackCounts: summary, all: sd.feedback } }];
}

// WRITE
const agentId = body.agentId;
const comment = (body.comment || '').toString().trim();
if (!agentId || !comment) {
  return [{ json: { ok: false, error: 'agentId and comment required' } }];
}
sd.feedback[agentId] = sd.feedback[agentId] || [];
sd.feedback[agentId].push({
  at: new Date().toISOString(),
  comment: comment.slice(0, 5000),
  source: body.source || 'ui'
});
if (sd.feedback[agentId].length > 100) {
  sd.feedback[agentId] = sd.feedback[agentId].slice(-100);
}
return [{ json: { ok: true, agentId, totalFeedback: sd.feedback[agentId].length } }];

